class CacheManager {
  final LocalStorageManager _storage;

  CacheManager(this._storage);

  Future<void> cacheContent(String key, Map<String, dynamic> content, {Duration? ttl}) async {
    final cacheData = {
      'content': content,
      'timestamp': DateTime.now().toIso8601String(),
      'ttl': ttl?.inSeconds,
    };
    await _storage.saveCachedData(key, cacheData);
  }

  Map<String, dynamic>? getCachedContent(String key) {
    final cacheData = _storage.getCachedData(key);
    if (cacheData == null) return null;

    final timestamp = DateTime.parse(cacheData['timestamp']);
    final ttl = cacheData['ttl'];

    if (ttl != null) {
      final expiryTime = timestamp.add(Duration(seconds: ttl));
      if (DateTime.now().isAfter(expiryTime)) {
        _storage.removeCachedData(key);
        return null;
      }
    }

    return cacheData['content'];
  }

  Future<void> clearExpiredCache() async {
    final keys = _storage.getAllKeys();
    for (final key in keys) {
      if (key.startsWith('cached_data_')) {
        final cacheKey = key.replaceFirst('cached_data_', '');
        getCachedContent(cacheKey);
      }
    }
  }
}

